const fs = require('fs');
const queuePath = '/home/node/queue.json';
const biblePath = '/home/node/character-bible.json';

let queue, bible;
try {
  queue = JSON.parse(fs.readFileSync(queuePath, 'utf8'));
} catch (e) {
  throw new Error('Failed to read queue.json: ' + e.message);
}
try {
  bible = JSON.parse(fs.readFileSync(biblePath, 'utf8'));
} catch (e) {
  throw new Error('Failed to read character-bible.json: ' + e.message);
}

const nextEpisode = queue.episodes.find(ep => ep.status === 'pending');
if (!nextEpisode) {
  throw new Error('No pending episodes in queue');
}

return [{ json: { ...nextEpisode, characterBible: bible } }];

const fs = require('fs');
const data = $input.first().json;
let envMap = {};
try {
  const raw = fs.readFileSync('/proc/1/environ', 'utf8');
  raw.split('\0').forEach(line => { const eq = line.indexOf('='); if (eq > 0) envMap[line.slice(0, eq)] = line.slice(eq + 1); });
} catch(e) {}
const env = {
  OLLAMA_MODEL: envMap.OLLAMA_MODEL || 'mistral',
  KIE_AI_API_KEY: envMap.KIE_AI_API_KEY || '',
  IMGBB_API_KEY: envMap.IMGBB_API_KEY || '',
  POLLINATIONS_API_KEY: envMap.POLLINATIONS_API_KEY || '',
  DISCORD_WEBHOOK_URL: envMap.DISCORD_WEBHOOK_URL || '',
  FACEBOOK_PAGE_ID: envMap.FACEBOOK_PAGE_ID || '',
  FACEBOOK_ACCESS_TOKEN: envMap.FACEBOOK_ACCESS_TOKEN || ''
};
return [{ json: { ...data, env } }];

const fs = require('fs');
const data = $input.first().json;
const workDir = '/home/node/.n8n/episodes/episode_' + data.episode_number;

if (!fs.existsSync(workDir)) {
  fs.mkdirSync(workDir, { recursive: true });
}

return [{ json: { ...data, workDir: workDir } }];

const input = $input.first().json;
const queueData = $('Carry Episode Data Forward').first().json;

let rawText = '';
if (input.message && input.message.content) {
  rawText = input.message.content;
} else if (typeof input === 'string') {
  rawText = input;
} else {
  rawText = JSON.stringify(input);
}

rawText = rawText.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();

function repairJson(s) {
  s = s.replace(/[\x00-\x1f]/g, m => m === '\n' || m === '\t' ? m : '');
  s = s.replace(/,\s*([}\]])/g, '$1');
  let braces = 0, inStr = false, esc = false;
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (esc) { esc = false; continue; }
    if (c === '\\') { esc = true; continue; }
    if (c === '"') inStr = !inStr;
    if (!inStr) { if (c === '{') braces++; if (c === '}') braces--; }
  }
  while (braces > 0) { s += '}'; braces--; }
  if (inStr) { s = s.slice(0, s.lastIndexOf('"')) + '"' + '}'.repeat(Math.max(0,braces+1)); }
  return s;
}

let episode;
try {
  episode = typeof rawText === 'object' ? rawText : JSON.parse(rawText);
} catch (e) {
  try {
    episode = JSON.parse(repairJson(rawText));
  } catch (e2) {
    const match = rawText.match(/\{[\s\S]*\}/);
    if (match) {
      try { episode = JSON.parse(match[0]); } catch(e3) { episode = JSON.parse(repairJson(match[0])); }
    } else {
      throw new Error('Could not parse episode JSON: ' + e.message + ' Raw: ' + rawText.slice(0, 300));
    }
  }
}

if (!episode.scenes || !Array.isArray(episode.scenes)) {
  throw new Error('Episode missing scenes array');
}

const narratorParts = [];
if (episode.narrator_intro) narratorParts.push(episode.narrator_intro);
episode.scenes.forEach(s => {
  if (s.narrator_vo) narratorParts.push(s.narrator_vo);
});
if (episode.narrator_outro) narratorParts.push(episode.narrator_outro);
const fullNarratorScript = narratorParts.join(' ... ');

const scenes = episode.scenes.map((scene, idx) => ({
  json: {
    episode_number: queueData.episode_number,
    episode_title: episode.episode_title || 'Untitled Episode',
    cliffhanger: episode.cliffhanger || '',
    fullNarratorScript: fullNarratorScript,
    totalScenes: episode.scenes.length,
    sceneIndex: idx,
    scene_number: scene.scene_number || (idx + 1),
    location: scene.location || 'villa',
    characters: scene.characters || [],
    visual_prompt: scene.visual_prompt || scene.imagePrompt || '',
    narrator_vo: scene.narrator_vo || '',
    action: scene.action || '',
    dialogue: scene.dialogue || '',
    mood: scene.mood || 'dramatic',
    duration_seconds: scene.duration_seconds || 5,
    characterBible: queueData.characterBible || {},
    workDir: '/home/node/.n8n/episodes/episode_' + queueData.episode_number
  }
}));

return scenes;

const item = $input.item.json;
const sceneData = $('Process Scenes One by One').first().json;

let refinedPrompt = '';
if (item.message && item.message.content) {
  refinedPrompt = item.message.content;
} else {
  refinedPrompt = sceneData.visual_prompt;
}

refinedPrompt = refinedPrompt.replace(/```/g, '').replace(/^\s*prompt:\s*/i, '').trim();

const characters = sceneData.characters || [];
const bible = (sceneData.characterBible || {}).characters || {};
let seed = sceneData.scene_number * 1000;
if (characters.length > 0 && bible[characters[0]]) {
  seed = bible[characters[0]].seed || seed;
}

const apiKey = $('Parse Queue & Find Next Episode').first().json.env.POLLINATIONS_API_KEY || '';
const imageUrl = 'https://gen.pollinations.ai/image/' + encodeURIComponent(refinedPrompt) + '?width=1080&height=1920&nologo=true&seed=' + seed + '&model=flux&key=' + apiKey;

return {
  json: {
    ...sceneData,
    refinedPrompt: refinedPrompt,
    imageUrl: imageUrl,
    imageSeed: seed
  }
};

const sceneData = $('Prepare Image Request').first().json;
const binaryData = $('Generate Image (Pollinations)').first().binary;
const binaryKey = Object.keys(binaryData || {})[0];
let imageBase64 = '';
if (binaryKey && binaryData[binaryKey]) {
  imageBase64 = binaryData[binaryKey].data;
}
return {
  json: {
    ...sceneData,
    imageBase64: imageBase64
  }
};

const item = $input.item.json;
const sceneData = $('Prepare imgbb Upload').first().json;

let publicImageUrl = '';
if (item.data && item.data.url) {
  publicImageUrl = item.data.url;
} else if (item.data && item.data.display_url) {
  publicImageUrl = item.data.display_url;
} else {
  throw new Error('imgbb upload failed: ' + JSON.stringify(item).slice(0, 300));
}

return {
  json: {
    ...sceneData,
    publicImageUrl: publicImageUrl
  }
};

const item = $input.item.json;
const sceneData = $('Prepare Kling Request').first().json;

const taskId = item.task_id || item.id || (item.data ? (item.data.task_id || item.data.id) : '') || '';
if (!taskId) {
  throw new Error('No task_id from Kling API: ' + JSON.stringify(item).slice(0, 300));
}

return {
  json: {
    ...sceneData,
    klingTaskId: taskId,
    pollRetries: 0,
    maxRetries: 15
  }
};

const item = $input.item.json;
const prevData = $('Setup Polling State').first().json;

const status = item.status || (item.data ? item.data.status : '') || 'unknown';
const retries = (prevData.pollRetries || 0) + 1;

if (status === 'completed' || status === 'succeed' || status === 'success') {
  const videoUrl = (item.output ? item.output.video_url : '') || (item.data ? (item.data.output ? item.data.output.video_url : item.data.video_url) : '') || item.video_url || '';
  return {
    json: {
      ...prevData,
      klingStatus: 'completed',
      videoUrl: videoUrl,
      pollRetries: retries
    }
  };
} else if (status === 'failed' || status === 'error') {
  throw new Error('Kling video generation failed for scene ' + prevData.scene_number);
} else if (retries >= (prevData.maxRetries || 15)) {
  throw new Error('Kling polling timeout after ' + retries + ' retries for scene ' + prevData.scene_number);
} else {
  return {
    json: {
      ...prevData,
      klingStatus: 'processing',
      pollRetries: retries
    }
  };
}

const firstScene = $('Parse Episode & Extract Scenes').first().json;
const env = $('Parse Queue & Find Next Episode').first().json.env || {};
return [{
  json: {
    fullNarratorScript: firstScene.fullNarratorScript || 'Welcome to Fruit Love Island!',
    episode_number: firstScene.episode_number,
    episode_title: firstScene.episode_title,
    cliffhanger: firstScene.cliffhanger || '',
    workDir: firstScene.workDir,
    totalScenes: firstScene.totalScenes,
    env: env
  }
}];

const { execSync } = require('child_process');
const fs = require('fs');
const ep = $('Prepare Voiceover Request').first().json;
const workDir = ep.workDir;
const totalScenes = ep.totalScenes || 6;

// Build concat file listing all scene clips
let concatContent = '';
for (let i = 1; i <= totalScenes; i++) {
  const clipPath = workDir + '/clip_' + i + '.mp4';
  if (fs.existsSync(clipPath)) {
    concatContent += "file '" + clipPath + "'\n";
  }
}

const concatFile = workDir + '/concat_list.txt';
fs.writeFileSync(concatFile, concatContent);

const voiceover = workDir + '/voiceover.mp3';
const output = workDir + '/final_episode_' + ep.episode_number + '.mp4';

// Concat clips, then mix voiceover audio
if (fs.existsSync(voiceover)) {
  execSync('ffmpeg -y -f concat -safe 0 -i ' + concatFile + ' -i ' + voiceover + ' -c:v copy -map 0:v:0 -map 1:a:0 -shortest ' + output, { timeout: 300000 });
} else {
  execSync('ffmpeg -y -f concat -safe 0 -i ' + concatFile + ' -c copy ' + output, { timeout: 300000 });
}

return [{ json: { status: 'ffmpeg_done', episode_number: ep.episode_number, episode_title: ep.episode_title, workDir: workDir, cliffhanger: ep.cliffhanger, videoPath: output } }];

const captionResponse = $input.first().json;
const epData = $('Prepare Voiceover Request').first().json;

let caption = 'New episode of Fruit Love Island!';
if (captionResponse.message && captionResponse.message.content) {
  caption = captionResponse.message.content;
}

return [{
  json: {
    caption: caption,
    videoPath: epData.workDir + '/final_episode_' + epData.episode_number + '.mp4',
    episode_number: epData.episode_number,
    episode_title: epData.episode_title || 'Fruit Love Island',
    workDir: epData.workDir
  }
}];

const fs = require('fs');
const { execSync } = require('child_process');
const data = $input.first().json;
const envData = $('Parse Queue & Find Next Episode').first().json.env;
const pageId = envData.FACEBOOK_PAGE_ID;
const accessToken = envData.FACEBOOK_ACCESS_TOKEN;

if (!pageId || !accessToken) {
  throw new Error('Missing FACEBOOK_PAGE_ID or FACEBOOK_ACCESS_TOKEN env vars');
}

const videoPath = data.videoPath;
if (!videoPath || !fs.existsSync(videoPath)) {
  throw new Error('Video file not found: ' + videoPath);
}

// Use curl for multipart video upload to Facebook Graph API
const caption = (data.caption || 'New Fruit Love Island episode!').replace(/'/g, "'\''");
const curlCmd = "curl -s -X POST " +
  "'https://graph-video.facebook.com/v19.0/" + pageId + "/videos' " +
  "-F 'access_token=" + accessToken + "' " +
  "-F 'description=" + caption + "' " +
  "-F 'title=" + (data.episode_title || 'Fruit Love Island').replace(/'/g, "'\''") + "' " +
  "-F 'source=@" + videoPath + "'";

const result = execSync(curlCmd, { timeout: 300000 }).toString();
let fbResponse;
try {
  fbResponse = JSON.parse(result);
} catch (e) {
  throw new Error('Facebook API returned invalid JSON: ' + result.slice(0, 500));
}

if (fbResponse.error) {
  throw new Error('Facebook API error: ' + fbResponse.error.message);
}

return [{ json: { ...data, fbVideoId: fbResponse.id || '', fbResponse: fbResponse } }];

const fs = require('fs');
const epData = $('Prepare Facebook Upload').first().json;
const queuePath = '/home/node/queue.json';

try {
  const queue = JSON.parse(fs.readFileSync(queuePath, 'utf8'));
  const ep = queue.episodes.find(e => e.episode_number === epData.episode_number);
  if (ep) {
    ep.status = 'published';
    ep.published_at = new Date().toISOString();
  }
  fs.writeFileSync(queuePath, JSON.stringify(queue, null, 2));
} catch (e) {
  // Non-fatal: log but don't block the pipeline
}

return [{ json: { status: 'published', episode_number: epData.episode_number, episode_title: epData.episode_title } }];
